#include<bits/stdc++.h>
using namespace std;
const int N=400010,B=10000,M=41;
int a[N],phi[N],p[M][N],P,C,n;
long long c[M];
int up[N],p1[M][N],p2[M][N],tot,m;
int fastpow(int k,int id)
{
    return 1ll*p1[id][k%B]*p2[id][k/B]%phi[id];
}
int tower(int i,int k,int id)
{
    if(id==tot)
    {
        return 0;
    }
    if(k==0)
    {
        return a[i]%phi[id];

    }
    if(C==1||(k-1<=up[i]&&p[k-1][i]<phi[id+1]))
    {
        return fastpow(tower(i,k-1,id+1),id);
    }
    else
    {
        return fastpow(tower(i,k-1,id+1)+phi[id+1],id);
    }
}
struct segment_tree
{
    long long sum[N*4];
    int cnt[N*4];
    void pushup(int x)
    {
        sum[x]=(sum[x<<1]+sum[x<<1|1])%P;
        cnt[x]=min(cnt[x<<1],cnt[x<<1|1]);
    }
    void init(int x,int l,int r)
    {
        if(l==r)
        {
            sum[x]=a[l];
            cnt[x]=0;
            return;
        }
        int mid=(l+r)>>1;
        init(x<<1,l,mid);
        init(x<<1|1,mid+1,r);
        pushup(x);
    }
    void update(int x,int l,int r,int u,int v)
    {
        if(cnt[x]>=tot)
        {
            return;
        }
        if(l==r)
        {
            sum[x]=tower(l,cnt[x]+1,1);
            cnt[x]++;
            return;
        }
        int mid=(l+r)>>1;
        if(u<=mid)
        {
            update(x<<1,l,mid,u,v);
        }
        if(v>mid)
        {
            update(x<<1|1,mid+1,r,u,v);
        }
        pushup(x);
    }
    long long query(int x,int l,int r,int u,int v)
    {
        if(u<=l&&r<=v)
        {
            return sum[x];
        }
        int mid=(l+r)>>1;
        if(v<=mid)
        {
            return query(x<<1,l,mid,u,v);
        }
        if(u>mid)
        {
            return query(x<<1|1,mid+1,r,u,v);
        }
        return (query(x<<1,l,mid,u,v)+query(x<<1|1,mid+1,r,u,v))%P;
    }
}t;
int calcphi(int x)
{
    int ans=x;
    for(int i=2;1ll*i*i<=x;i++)
    {
        if(x%i!=0)
        {
            continue;
        }
        ans=1ll*ans*(i-1)/i;
        while(x%i==0)
        {
            x/=i;
        }
    }
    if(x>1)
    {
        ans=1ll*ans*(x-1)/x;
    }
    return ans;
}
void init()
{
    tot=1;
    phi[1]=P;
    while(phi[tot]>1)
    {
        phi[tot+1]=calcphi(phi[tot]);
        tot++;
    }
    for(int i=1;i<=tot;i++)
    {
        p1[i][0]=1;
        for(int j=1;j<=B;j++)
        {
            p1[i][j]=1ll*p1[i][j-1]*C%phi[i];
        }
        int z=p1[i][B];
        p2[i][0]=1;
        for(int j=1;j*B<=P*2;j++)
        {
            p2[i][j]=1ll*p2[i][j-1]*z%phi[i];
        }
    }
    int z=0;
    c[z]=1;
    while(c[z]<P&&z<=30)
    {
        z++;
        c[z]=c[z-1]*C;
    }
    z--;
    for(int i=1;i<=n;i++)
    {
        up[i]=0;
        p[0][i]=a[i];
        while(up[i]<=z&&p[up[i]][i]<=z)
        {
            p[up[i]+1][i]=p1[1][p[up[i]][i]];
            up[i]++;
        }
    }
}
int main()
{
    scanf("%d%d%d%d",&n,&m,&P,&C);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    init();
    t.init(1,1,n);
    for(int i=1;i<=m;i++)
    {
        int op,l,r;
        scanf("%d%d%d",&op,&l,&r);
        if(op==0)
        {
            t.update(1,1,n,l,r);
        }
        else
        {
            printf("%lld\n",t.query(1,1,n,l,r));
        }
    }
    return 0;
}
